import json

with open('baseline-packages.json') as f:
    baseline = json.load(f)
with open('after-cpm-packages.json') as f:
    after = json.load(f)

# Build lookup: {project_basename: {framework: {pkg_id: resolved_version}}}
def build_lookup(data):
    result = {}
    for p in data['projects']:
        name = p['path'].split('/')[-1]
        result[name] = {}
        for fw in p['frameworks']:
            result[name][fw['framework']] = {}
            for pkg in fw['topLevelPackages']:
                result[name][fw['framework']][pkg['id']] = pkg['resolvedVersion']
    return result

b = build_lookup(baseline)
a = build_lookup(after)

changes = []
unchanged = []
for proj in sorted(set(list(b.keys()) + list(a.keys()))):
    for fw in sorted(set(list(b.get(proj, {}).keys()) + list(a.get(proj, {}).keys()))):
        b_pkgs = b.get(proj, {}).get(fw, {})
        a_pkgs = a.get(proj, {}).get(fw, {})
        all_pkgs = sorted(set(list(b_pkgs.keys()) + list(a_pkgs.keys())))
        for pkg in all_pkgs:
            bv = b_pkgs.get(pkg)
            av = a_pkgs.get(pkg)
            label = f'{proj} ({fw})'
            if bv and av and bv == av:
                unchanged.append((label, pkg, av))
            elif bv and av and bv != av:
                changes.append((label, pkg, bv, av, 'Aligned to highest version'))
            elif bv and not av:
                changes.append((label, pkg, bv, '-', 'Removed'))
            elif not bv and av:
                changes.append((label, pkg, '-', av, 'Added'))

print('=== CHANGES ===')
if changes:
    for c in changes:
        print(f'  {c[0]} | {c[1]} | {c[2]} -> {c[3]} | {c[4]}')
else:
    print('  (none)')

print()
print('=== UNCHANGED ===')
for u in unchanged:
    print(f'  {u[0]} | {u[1]} | {u[2]}')
"

